sql:
SELECT measurement_id, MAX(point_index) AS max_point_index
FROM points
GROUP BY measurement_id;

external_knowledge:
- 'Aviators sailing through the sonic barrier' refers to pilots conducting supersonic flight tests;
- 'Alice Johnson's supersonic odyssey' refers to the period from January 1, 2023, to December 31, 2023, when Alice Johnson conducted supersonic flight tests;
- 'What were the voyages like' refers to the descriptions of the flight tests conducted.

sql:
SELECT pilot_name, license_number
FROM pilots
ORDER BY pilot_name DESC;

SELECT AVG(x_coordinate) AS avg_x, AVG(y_coordinate) AS avg_y, AVG(z_coordinate) AS avg_z
FROM points
WHERE measurement_id = 1;

SELECT DISTINCT pilots.pilot_name
FROM pilots
INNER JOIN flight_tests ON pilots.pilot_id = flight_tests.pilot_id;

SELECT aircraft_name, owner
FROM aircrafts
WHERE aircraft_id = 1;
